import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithCommentMarker() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char commentChar = '#';

        CSVFormat newFormat = baseFormat.withCommentMarker(commentChar);

        assertNotNull(newFormat);
        assertNotSame(baseFormat, newFormat);
        assertEquals(Character.valueOf(commentChar), newFormat.getCommentMarker());

        // Also test with default comment marker null
        CSVFormat formatWithNullComment = baseFormat.withCommentMarker('\0');
        // '\0' is a valid char but likely not a comment marker, test that it is set
        assertEquals(Character.valueOf('\0'), formatWithNullComment.getCommentMarker());
    }
}
